iv>\\n<!-- \\/wp:woocommerce\\/checkout-order-note-block --><!-- wp:woocommerce\\/checkout-terms-block -->\\n<div class=\\\"wp-block-woocommerce-checkout-terms-block\\\">\\u00a0<\\/div>\\n<!-- \\/wp:woocommerce\\/checkout-terms-block --><!-- wp:woocommerce\\/checkout-actions-block -->\\n<div class=\\\"wp-block-woocommerce-checkout-actions-block\\\">\\u00a0<\\/div>\\n<!-- \\/wp:woocommerce\\/checkout-actions-block --><\\/div>\\n<!-- \\/wp:woocommerce\\/checkout-fields-block --><!-- wp:woocommerce\\/checkout-totals-block -->\\n<div class=\\\"wp-block-woocommerce-checkout-totals-block\\\"><!-- wp:woocommerce\\/checkout-order-summary-block -->\\n<div class=\\\"wp-block-woocommerce-checkout-order-summary-block\\\"><!-- wp:woocommerce\\/checkout-order-summary-cart-items-block -->\\n<div class=\\\"wp-block-woocommerce-checkout-order-summary-cart-items-block\\\">\\u00a0<\\/div>\\n<!-- \\/wp:woocommerce\\/checkout-order-summary-cart-items-block --><!-- wp:woocommerce\\/checkout-order-summary-coupon-form-block -->\\n<div class=\\\"wp-block-woocommerce-checkout-order-summary-coupon-form-block\\\">\\u00a0<\\/div>\\n<!-- \\/wp:woocommerce\\/checkout-order-summary-coupon-form-block --><!-- wp:woocommerce\\/checkout-order-summary-subtotal-block -->\\n<div class=\\\"wp-block-woocommerce-checkout-order-summary-subtotal-block\\\">\\u00a0<\\/div>\\n<!-- \\/wp:woocommerce\\/checkout-order-summary-subtotal-block --><!-- wp:woocommerce\\/checkout-order-summary-fee-block -->\\n<div class=\\\"wp-block-woocommerce-checkout-order-summary-fee-block\\\">\\u00a0<\\/div>\\n<!-- \\/wp:woocommerce\\/checkout-order-summary-fee-block --><!-- wp:woocommerce\\/checkout-order-summary-discount-block -->\\n<div class=\\\"wp-block-woocommerce-checkout-order-summary-discount-block\\\">\\u00a0<\\/div>\\n<!-- \\/wp:woocommerce\\/checkout-order-summary-discount-block --><!-- wp:woocommerce\\/checkout-order-summary-shipping-block -->\\n<div class=\\\"wp-block-woocommerce-checkout-order-summary-shipping-block\\\">\\u00a0<\\/div>\\n<!-- \\/wp:woocommerce\\/checkout-order-summary-shipping-block --><!-- wp:woocommerce\\/checkout-order-summary-taxes-block -->\\n<div class=\\\"wp-block-woocommerce-checkout-order-summary-taxes-block\\\">\\u00a0<\\/div>\\n<!-- \\/wp:woocommerce\\/checkout-order-summary-taxes-block --><\\/div>\\n<!-- \\/wp:woocommerce\\/checkout-order-summary-block --><\\/div>\\n<!-- \\/wp:woocommerce\\/checkout-totals-block --><\\/div>\\n<!-- \\/wp:woocommerce\\/checkout -->\"},\"elements\":[],\"widgetType\":\"text-editor\"}],\"isInner\":false},{\"id\":\"3bc5e71\",\"elType\":\"container\",\"settings\":{\"flex_direction\":\"row\",\"flex_gap\":{\"unit\":\"px\",\"size\":0,\"column\":\"0\",\"row\":\"0\"},\"flex_justify_content\":\"flex-start\",\"flex_align_items\":\"center\"},\"elements\":[{\"id\":\"5f5e93b\",\"elType\":\"widget\",\"settings\":{\"text\":\"\\u00bfDudas con tu pedido? Consultar soporte\",\"link\":{\"url\":\"http:\\/\\/localhost:8000\\/centro-de-soporte\\/\",\"is_external\":\"\",\"nofollow\":\"\",\"custom_attributes\":\"\"},\"background_color\":\"#FF6B00\",\"_element_width\":\"auto\",\"__globals__\":{\"typography_typography\":\"globals\\/typography?id=secondary\"}},\"elements\":[],\"widgetType\":\"button\"}],\"isInner\":false}]'),(998,121,'_elementor_page_assets','a:1:{s:7:\"scripts\";a:1:{i:0;s:18:\"elementor-frontend\";}}'),(999,121,'_elementor_css','a:6:{s:4:\"time\";i:1776664250;s:5:\"fonts\";a:0:{}s:5:\"icons\";a:0:{}s:20:\"dynamic_elements_ids\";a:0:{}s:6:\"status\";s:4:\"file\";i:0;s:0:\"\";}'),(1000,121,'_elementor_element_cache','{\"timeout\":1776757857,\"value\":{\"content\":\"<div class=\"elementor-element elementor-element-42883474 e-flex e-con-boxed e-con e-parent\" data-id=\"42883474\" data-element_type=\"container\" data-e-type=\"container\">nttttt<div class=\"e-con-inner\">ntt[elementor-element k=\"17b8ee008151da3bcc649f302768a09c\" data=\"\"]ttt</div>ntttt</div>ntt\",\"scripts\":[],\"styles\":[]}}'),(1001,121,'_elementor_page_settings'