INSERT INTO `wp_snippets` VALUES (1,'Hacer que los nombres de archivos subidos estén en minúsculas','Asegura que las subidas de imágenes y archivos tengan nombres de archivo en minúsculas.\n\nEsto es un fragmento de código de ejemplo. Siéntente libre de usarlo, editarlo o eliminarlo.','add_filter( \'sanitize_file_name\', \'mb_strtolower\' );','sample, media','global',0,10,0,'2026-04-18 18:33:20',1,NULL),(2,'Desactivar barra de administración','Desactiva la barra de administración de WordPress para todos excepto para los administradores.\n\nEsto es un fragmento de código de ejemplo. Siéntente libre de usarlo, editarlo o eliminarlo.','add_action( \'wp\', function () {\n	if ( ! current_user_can( \'manage_options\' ) ) {\n		show_admin_bar( false );\n	}\n} );','sample, admin-bar','front-end',0,10,0,'2026-04-18 18:33:20',1,NULL),(3,'Permitir emoticonos','Permite la conversión de emoticonos en lugares oscuros.\n\nEsto es un fragmento de código de ejemplo. Siéntente libre de usarlo, editarlo o eliminarlo.','add_filter( \'widget_text\', \'convert_smilies\' );\nadd_filter( \'the_title\', \'convert_smilies\' );\nadd_filter( \'wp_title\', \'convert_smilies\' );\nadd_filter( \'get_bloginfo\', \'convert_smilies\' );','sample','global',0,10,0,'2026-04-18 18:33:20',1,NULL),(4,'Año actual','Shortcode para insertar el año actual en una entrada o página…\n\nEsto es un fragmento de código de ejemplo. Siéntente libre de usarlo, editarlo o eliminarlo.','<?php echo date( \'Y\' ); ?>','sample, dates','content',0,10,0,'2026-04-18 18:33:20',1,NULL),(5,'Botón soporte en checkout','','add_action( \'woocommerce_review_order_after_submit\', \'imaginamos_soporte_button\', 20 );\nfunction imaginamos_soporte_button() {\n    $soporte_url = home_url( \'/centro-de-soporte/\' ); \n    echo \'<a href=\"\' . esc_url( $soporte_url ) . \'\" class=\"imaginamos-soporte-btn\">¿Dudas con tu pedido? Consultar soporte</a>\';\n}\n\nadd_action( \'wp_head\', \'imaginamos_soporte_button_styles\' );\nfunction imaginamos_soporte_button_styles() {\n    if ( is_checkout() ) {\n        echo \'<style>\n            .imaginamos-soporte-btn {\n                display: block; width: 100%; margin-top: 15px; padding: 16px 24px;\n                background-color: #FF6B00; color: #FFFFFF !important; font-weight: 700;\n                text-align: center; text-decoration: none; border-radius: 8px;\n                border: none; font-size: 16px; transition: background 0.2s ease;\n            }\n            .imaginamos-soporte-btn:hover { background-color: #E55A00; color: #FFFFFF !important; }\n        </style>\';\n    }\n}','','global',0,10,1,'2026-04-18 19:05:24',1,NULL);
/*!40000 ALTER TABLE `wp_snippets` ENABLE KEYS */;
