ew_docs','Learn about Deposit schedules','https://woocommerce.com/document/woopayments/deposits/deposit-schedule/?utm_source=inbox_note&utm_medium=product&utm_campaign=view_docs#available-funds','unactioned','',NULL,NULL),(760,53,'sirt-woo-2024-11-xss-admin','See available updates','http://localhost:8000/wp-admin/update-core.php?','unactioned','',NULL,NULL),(761,53,'sirt-woo-2024-11-xss-admin','Dismiss','#','actioned','',NULL,NULL),(762,54,'paypal-braintree-sdk-depreciation-2025-02-20-button','Upgrade now','http://localhost:8000/wp-admin/wp-admin/plugins.php','actioned','',NULL,NULL),(763,55,'uk-vat-notice-button-2025-04-30','Learn more about this extension','https://wordpress.org/plugins/eu-vat-for-woocommerce/','actioned','',NULL,NULL),(764,56,'paypal-braintree-sdk-depreciation-2025-05-30-button','Update now','http://localhost:8000/wp-admin/wp-admin/plugins.php','unactioned','',NULL,NULL);
